    """Read a file based on its format and compression."""
    opener = {
        '.gz': gzip.open,
        '.bz2': bz2.open,
        None: open,
    }[comp_ext]

    read_kwargs = {'encoding': 'utf-8'} if comp_ext else {}

    if fmt == '.csv':
        with opener(filepath, 'rt', **read_kwargs) as f:
            return pd.read_csv(f)
    elif fmt == '.parquet':
        return pd.read_parquet(filepath)
