        'where': _extract_tokens(stmt, 'WHERE', ['GROUP', 'HAVING', 'ORDER', 'LIMIT', 'OFFSET']),
        'group_by': _parse_token_list(stmt, 'GROUP', ['BY', 'HAVING', 'ORDER', 'LIMIT', 'OFFSET']),
        'having': _extract_tokens(stmt, 'HAVING', ['ORDER', 'LIMIT', 'OFFSET']),
        'order_by': _parse_order_by(stmt),
        'limit': _find_number(stmt, 'LIMIT', ['OFFSET']),
        'offset': _find_number(stmt, 'OFFSET', ['LIMIT']),
        'window_functions': _parse_window_functions(stmt),
    }


def _extract_tokens(stmt, keyword: str, stop_keywords: list) -> str:
    return ' '.join(t.value for t in stmt.flatten()
                    if _in_clause(t, keyword, stop_keywords) and t.value.strip())


def _parse_token_list(stmt, keyword: str, stop_keywords: list) -> list:
    items = []
    for t in stmt.flatten():
        if _in_clause(t, keyword, stop_keywords):
            v = t.value.strip()
            if v and v != ',':
                items.append(v)
    return items


def _in_clause(token, keyword: str, stop_keywords: list) -> bool:
    if token.ttype not in Keyword:
        return True
    k = token.value.upper()
    if k == keyword:
        return False  # Skip the keyword itself
    return k not in stop_keywords


def _find_number(stmt, keyword: str, stop_keywords: list) -> int | None:
    in_clause = False
    for t in stmt.flatten():
        if token.ttype in Keyword:
            in_clause = (token.value.upper() == keyword)
            if not in_clause or token.value.upper() in stop_keywords:
                in_clause = False
        if in_clause and t.value.strip():
            val = t.value.strip()
            if val.isdigit() or (val.startswith('-') and val[1:].isdigit()):
                return int(val)
    return None


def _parse_select(stmt) -> tuple:
    selects, distinct = [], False
    in_select = False
    for t in stmt.flatten():
        v = t.value.strip()
        if t.ttype in Keyword:
            if v.upper() == 'SELECT':
                in_select = True
                continue
            elif v.upper() in ['FROM', 'WHERE', 'GROUP', 'HAVING', 'ORDER', 'LIMIT', 'OFFSET']:
                in_select = False
                continue
        if in_select and v:
            if v.upper() == 'DISTINCT':
                distinct = True
            else:
                selects.append(v)
    return selects, distinct


def _parse_window_functions(stmt) -> list:
    """Extract window function specifications from the SELECT clause."""
    window_funcs, current_expr = [], []
    in_select = False

    for token in stmt.flatten():
        v = token.value.strip()
        if token.ttype in Keyword:
            if v.upper() == 'SELECT':
                in_select = True
                continue
            elif v.upper() in ['FROM', 'WHERE', 'GROUP', 'HAVING', 'ORDER', 'LIMIT', 'OFFSET']:
                in_select = False
                if current_expr:
                    window_funcs.append(_extract_window_spec(''.join(current_expr).strip()))
