    over_match = re.search(r'\bOVER\s*\(\s*\)', expr, re.IGNORECASE)

    if over_match:
        func_match = re.match(r'^([^(]+)\s+OVER\s*\(\s*\)', expr, re.IGNORECASE)
        if func_match:
            return {
                'function': func_match.group(1).strip().upper(),
                'partition_by': [],
                'order_by': [],
                'frame_clause': None,
            }

    over_start = re.search(r'\bOVER\s*\(', expr, re.IGNORECASE)
    if over_start:
        start = over_start.end()
        depth = 1
        end = start
        for i, c in enumerate(expr[start:]):
            if c == '(':
                depth += 1
            elif c == ')':
                depth -= 1
                if depth == 0:
                    end = start + i
                    break

        body = expr[start:end].strip()
        func_part = expr[:over_start.start()].strip()
        func = re.match(r'^(.*?)(?:\s+OVER)', func_part, re.IGNORECASE)
        func_name = func.group(1).strip() if func else func_part

        return _parse_window_body(body, func_name.strip())

    return None


def _parse_window_body(window_body: str, func: str) -> dict:
    """Parse the body of a window specification."""
    frame_clause = None
    body_for_parse = window_body

    m = re.search(r'(?:(ROWS|RANGE)\b.*)$', window_body, re.IGNORECASE)
    if m:
        frame_clause = m.group(0).strip()
        body_for_parse = window_body[:m.start()].strip()

    parsed = sqlparse.parse(f"SELECT {body_for_parse}")[0]
    partition_by = []
    order_by = []

    in_partition = False
    for t in parsed.flatten():
        v = t.value.strip()
        if t.ttype in Keyword:
            if v.upper() == 'PARTITION':
                in_partition = True
                continue
            elif v.upper() == 'BY':
                continue
            elif v.upper() in ['ORDER', 'ROWS', 'RANGE']:
                in_partition = False
        if in_partition and v and v != ',':
            partition_by.append(v.rstrip(','))

    in_order = False
    for t in parsed.flatten():
        v = t.value.strip()
        if t.ttype in Keyword:
            if v.upper() == 'ORDER':
                in_order = True
                continue
            elif v.upper() == 'BY':
                continue
            elif v.upper() in ['ROWS', 'RANGE', 'PARTITION']:
                in_order = False
        if in_order:
            if v.upper() == 'DESC' and order_by:
                order_by[-1] = (order_by[-1][0], True)
            elif v.upper() == 'ASC' and order_by:
                order_by[-1] = (order_by[-1][0], False)
            elif v and v != ',':
                order_by.append((v.rstrip(','), False))

    return {
        'function': func.upper(),
        'partition_by': partition_by,
        'order_by': order_by,
        'frame_clause': frame_clause,
    }


def _parse_from(stmt) -> dict:
    result = {'main_table': None, 'joins': []}
    in_from, in_join = False, False
    join_type = 'INNER'

    for token in stmt.tokens:
        if token.ttype in Keyword:
            v = token.value.upper()
            if v == 'FROM':
